
.card {
  width: 100%;
  max-width: 720px;
  background-color: var(--c-mint-cream);
  border: 3px solid var(--c-granite);
  box-shadow: 5px 5px 0px rgba(60, 73, 63, 0.16);
  display: flex;
  flex-direction: column;
  font-family: var(--font-archive);
  color: var(--c-granite);
  font-size: 13px;
  line-height: 1.35;
  margin: 0 auto;
}

.empty-state {
  text-align: center;
  color: var(--c-grey-olive);
  padding: 12px;
  font-style: italic;
  font-size: 0.85rem;
}

.fa-bao-content {
  padding: 10px;
}

.fa-bao-item {
  background: linear-gradient(135deg, var(--c-gold), #e8d5a3);
  border: 1.5px solid var(--c-granite);
  padding: 8px 12px;
  font-weight: bold;
  text-align: center;
}

// 储物袋
.storage-list {
  padding: 8px;
}

.category-section {
  margin-bottom: 6px;
  border: 1.5px solid var(--c-grey-olive);
}

.category-header {
  display: flex;
  align-items: center;
  padding: 6px 8px;
  background: var(--c-mint-cream);
  cursor: pointer;
  user-select: none;

  &:hover {
    background: var(--c-ash-grey);
  }
}

.category-icon {
  width: 22px;
  height: 22px;
  background: var(--c-sky);
  border: 1.5px solid var(--c-granite);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.65rem;
  font-weight: bold;
  margin-right: 8px;
}

.category-name {
  flex: 1;
  font-weight: bold;
  font-size: 0.85rem;
}

.category-count {
  background: var(--c-granite);
  color: #fff;
  padding: 1px 6px;
  font-size: 0.7rem;
}

.category-items {
  padding: 4px 8px 8px 38px;
}

.storage-item {
  padding: 3px 0;
  font-size: 0.85rem;
  border-bottom: 1px dashed var(--c-ash-grey);

  &:last-child {
    border-bottom: none;
  }
}

// 角色信息
.char-info {
  padding: 10px;
}

.info-row {
  display: flex;
  padding: 4px 0;
  border-bottom: 1px dashed var(--c-ash-grey);

  &:last-child {
    border-bottom: none;
  }
}

.info-label {
  width: 60px;
  font-weight: bold;
  color: var(--c-grey-olive);
  flex-shrink: 0;
}

.info-value {
  flex: 1;
}

.affinity-high {
  color: var(--c-celadon);
  font-weight: bold;
}

.affinity-low {
  color: var(--c-danger);
  font-weight: bold;
}

// 关系网
.relation-list {
  padding: 8px;
}

.relation-item {
  display: flex;
  align-items: center;
  padding: 5px 0;
  border-bottom: 1px dashed var(--c-ash-grey);
  gap: 8px;

  &:last-child {
    border-bottom: none;
  }
}

.rel-name {
  font-weight: bold;
  width: 80px;
}

.rel-affinity {
  font-size: 0.8rem;
  padding: 1px 6px;
  background: var(--c-ash-grey);
}

.rel-realm {
  font-size: 0.75rem;
  color: var(--c-grey-olive);
  margin-left: auto;
}

// 任务
.quest-section {
  padding: 10px;
}

.quest-row {
  display: flex;
  padding: 5px 0;
  border-bottom: 1px dashed var(--c-ash-grey);

  &:last-child {
    border-bottom: none;
  }
}

.quest-label {
  width: 60px;
  font-weight: bold;
  color: var(--c-grey-olive);
  flex-shrink: 0;
}

.quest-value {
  flex: 1;
}
