
.badge-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 10px;
  background: var(--c-granite);
  color: var(--c-mint-cream);
  font-size: 0.85rem;
  flex-wrap: wrap;
  gap: 4px;
}

.badge-left,
.badge-right {
  display: flex;
  align-items: center;
  gap: 10px;
}

.badge-day {
  font-weight: bold;
}

.badge-realm {
  .progress {
    color: var(--c-ash-grey);
    font-size: 0.75rem;
  }
}

.badge-location {
  font-weight: bold;
}

.badge-region {
  font-size: 0.75rem;
  color: var(--c-ash-grey);
}

.badge-lingshi {
  background: var(--c-gold);
  color: var(--c-granite);
  padding: 1px 6px;
  font-weight: bold;
  font-size: 0.75rem;
}
